const h = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const token = h['x-meta-token'];
const account = h['x-meta-account'];
if (!token || !account) {
  $execution.abort({ message: 'Missing Meta credentials' });
}
if (!body.source_audience_id) {
  $execution.abort({ message: 'source_audience_id is required' });
}
const ratio = Math.min(0.1, Math.max(0.01, parseFloat(body.ratio) || 0.02));
const country = String(body.country || 'GB').toUpperCase().slice(0, 2);
return [{ json: { token, account, source_id: String(body.source_audience_id), ratio, country } }];

const d = $input.item.json;
if (d.error) {
  return [{ json: { success: false, message: d.error.message || 'Meta API error', code: d.error.code } }];
}
return [{ json: { success: true, id: d.id, message: 'Lookalike audience created — may take a few minutes to populate' } }];
